head.script:
//==================================================================================================================
// id       : op_210_01_01b 
// 이름     : 본선계획수립대상
// 경로     : 물류/하역(인천)/계획/배치/
// 작 성 자 : 조성빈
// 작 업 일 : 2026-02-05
// 사용계정 : 내부
// 비고     :  ***
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//==================================================================================================================
scwin.onpageload = function() {

	scwin.lobranCd = $c.gus.cfIsNull($c.data.getMemInfo("lobranCd")) ? "" : $c.data.getMemInfo("lobranCd");  // 물류 점소 코드
	scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
	scwin.varvStDt = scwin.vCurDate.substring(0, 6) + "01";  // 입항예정일자 from(현재 날짜가 포함된 달의 시작 일자)
	scwin.varvEndDt = scwin.vCurDate.substring(0, 6) + $c.date.getLastDateOfMonth(scwin.vCurDate.substring(0, 6));  // 입항예정일자 to(현재 날짜가 포함된 달의 마지막 일자)

    scwin.vBasSdId = "/ui/ds/op/stvwrk/op_210_01_02b.xml";  // 본선작업계획상세조회
    scwin.vBasMnId = "op_210_01_02b";  // 본선작업계획상세조회

    //파일 업로드 위치
    scwin.systemPathKey =  DFWConstants.FILE_UPLOAD_SYSTEM_PATH ;
    scwin.systemPathVal =  "/cm/bc/cstmrcardmgnt/cstmrcardmgnt";

    scwin.curRow = "";
    scwin.curRow2 = "";

    scwin.tmp_colid = "";
    scwin.tmp_grdnm = "";
    scwin.tmp_staffNo      = "";
    scwin.tmp_staffNm   = "";

    const codeOptions = [
        { grpCd : "OP306", compID : "gr_cvsslInfo:wrkSeq" },
        { grpCd : "SD060", compID : "gr_hold:impExpClsCd" },

    ];
    $c.data.setCommonCode(codeOptions, scwin.setCommonCodeCallBack);

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
    }, {"delay":50});
};

scwin.setCommonCodeCallBack = async function(){
    co_ds_combo1_search.set("sysCd", "BerthNonUsableEBC");
    co_ds_combo1_search.set("queryId", "retriveLobranCodeList");
    var rs = await $c.sbm.execute(sbm_lobranCd);
    if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
        co_ds_combo1.setJSON(rs.responseJSON.GAUCE);
        co_ds_combo1.sort("code", 0);

        scwin.f_SetDefaultData();
    };
};

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function () {

	ica_arvStDt.setValue(scwin.varvStDt);  // 입항예정일자 from		
	ica_arvEndDt.setValue(scwin.varvEndDt);  // 입항예정일자 to	
	$c.gus.cfDisableAllBtn();

	acb_lobranCd.setValue(scwin.lobranCd);
	acb_lobranCd.focus();

    // $p.setTimeout(function() {
    //     acb_lobranCd.setValue("6AA");
    //     ica_arvStDt.setValue("20171124");
    //     ica_arvEndDt.setValue("20171124");
    // }, {"delay":50});
};

//-------------------------------------------------------------------------
// 본선작업계획현황조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
	// 검색조건 필수 입력 체크
  	if (!await $c.gus.cfValidate([acb_lobranCd, ica_arvStDt, ica_arvEndDt])) {
  		return;
	}
	// 조회일자 from ~ to 체크	
	if (!await $c.gus.cfIsAfterDate(ica_arvStDt.getValue(), ica_arvEndDt.getValue())) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // "시작일자가 종료일자 이전이어야 합니다."
		ica_arvStDt.focus();
		return;
	}
    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 본선작업계획 투입가능인원 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve2 = function () {
    $c.sbm.execute(sbm_retrieveMan);
};

//-------------------------------------------------------------------------
// 본선작업계획 hold별 물량정보 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve3 = async function () {
	ds_condition.set("cvsslMgntNo", ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(), "cvsslMgntNo"));
    var rs = await $c.sbm.execute(sbm_retrieveHold);
    if (rs.responseJSON.resultDataSet[0].Code == 0) {
        var rowCnt = ds_hold.getRowCount();
        txt_totalRows3.setValue(rowCnt);
    }
};

//-------------------------------------------------------------------------
// 본선작업계획 첨부파일 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve4 = async function () {
	ds_condition.set("cvsslMgntNo", ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(),"cvsslMgntNo"));
    var rs = await $c.sbm.execute(sbm_retrieveFile);
    if (rs.responseJSON.resultDataSet[0].Code == 0) {
        var fileJson = [];
        // 총 조회건수 표시
        if (ds_attach.getRowCount() > 0){
            // attachFileDesc   : "중기 배정 결과.xlsx"
            // attachFileId     : "0001"
            // attachFileNm     : "중기 배정 결과.xlsx"
            // attachFilePath   : "cm/bc/cstmrcardmgnt/cstmrcardmgnt/중기 배정 결과[1_10101_260211114802680].xlsx"
            // attachFileSiz    : "4113"
            // onReqNo          : "200708210378"
            // regDtm           : "02/11 11:48"
            // rowStatus        : "R"
            // selfTransClntNo  : "100477"
            // seq              : "1"
            for (var i = 0 ; i < ds_attach.getRowCount() ; i ++){
                var attachFilePath = ds_attach.getCellData(i, "attachFilePath")

                var fileStoredPath = attachFilePath.substr(0, attachFilePath.lastIndexOf('/')+1);
                var storedFileNm = attachFilePath.substr(attachFilePath.lastIndexOf('/')+1);

                var fileInfoData = {
                    FILE_EXPLAIN      : ds_attach.getCellData(i, "attachFileDesc")
                    , FILE_SIZE         : ds_attach.getCellData(i, "attachFileSiz")
                    , FILE_STORED_PATH  : fileStoredPath
                    , ORIGIN_FILE_NM    : ds_attach.getCellData(i, "attachFileNm")
                    , STORED_FILE_NM    : storedFileNm
                    , chk               : "0"
                    , evidClsNm         : ""
                    , hiddenKey         : ""
                    , preView           : ""
                    , receptYn          : ""
                    , rowStatus         : ds_attach.getCellData(i, "rowStatus")
                    , slipKndNm         : ""
                    , slipNo            : ""
                    , status            : ""
                }
                fileJson.push(fileInfoData);
            }
        }
        gr_attachFile.setData(fileJson);
    }
};

//-------------------------------------------------------------------------
// 저장 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_Save = async function () {  
	scwin.curRow = ds_cvsslInfo.getRowPosition();
    var modifyRowCnt = ds_cvsslInfo.getModifiedIndex().length
    if (modifyRowCnt > 0) {
		if (!await $c.gus.cfValidate([gr_cvsslInfo]) ) return;		
		if (await $c.win.confirm(MSG_CM_CRM_001)){
            $c.sbm.execute(sbm_save);
		}		
	}else{
		await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["본선계획수립대상"]); // @은(는) 변경된 사항이 없습니다
	}		
};

//-------------------------------------------------------------------------
// 저장 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_Save2 = async function () {  
	scwin.curRow2 = ds_hold.getRowPosition();
	var modifyRowCnt = ds_hold.getModifiedIndex().length
    if (modifyRowCnt > 0) {
		if (!await $c.gus.cfValidate([gr_hold]) ) return;		
		if (await $c.win.confirm(MSG_CM_CRM_001)){
            $c.sbm.execute(sbm_save2);
		}		
	}else{
		await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["Hold별 물량정보"]); // @은(는) 변경된 사항이 없습니다
	}		
};

 //-------------------------------------------------------------------------
 // 행추가
 //------------------------------------------------------------------------- 
scwin.f_AddRow = function (){
    var rowIndex = ds_hold.insertRow();
    ds_hold.setRowPosition(rowIndex);
    gr_hold.setFocusedCell(rowIndex, 0, false);

    ds_hold.setCellData(ds_hold.getRowPosition(),"cvsslMgntNo", ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(),"cvsslMgntNo"));
    ds_hold.setCellData(ds_hold.getRowPosition(),"holdNo", ds_hold.getRowPosition()+1);
    if (ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(),"ioClsNm")=="수입"){
        ds_hold.setCellData(ds_hold.getRowPosition(),"impExpClsCd", "I");
    } else {
        ds_hold.setCellData(ds_hold.getRowPosition(),"impExpClsCd", "O"); 		
    }
};

 //-------------------------------------------------------------------------
 // 행복사
 //------------------------------------------------------------------------- 
scwin.f_CopyRow = function (){
    var bfRow = ds_hold.getRowPosition();
    var rowIndex = ds_hold.insertRow();
    ds_hold.setRowPosition(rowIndex);
    gr_hold.setFocusedCell(rowIndex, 0, false);

    ds_hold.setCellData(ds_hold.getRowPosition(),"cvsslMgntNo", ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(),"cvsslMgntNo"));
    ds_hold.setCellData(ds_hold.getRowPosition(),"holdNo", ds_hold.getRowPosition()+1);
    if (ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(), "ioClsNm") == "수입"){
        ds_hold.setCellData(ds_hold.getRowPosition(),"impExpClsCd","I");
    } else {
        ds_hold.setCellData(ds_hold.getRowPosition(),"impExpClsCd","O"); 		
    }
    ds_hold.setCellData(ds_hold.getRowPosition(),"commCd", ds_hold.getCellData(bfRow,"commCd"));
    ds_hold.setCellData(ds_hold.getRowPosition(),"commNm", ds_hold.getCellData(bfRow,"commNm"));
    ds_hold.setCellData(ds_hold.getRowPosition(),"qty", ds_hold.getCellData(bfRow,"qty"));
    ds_hold.setCellData(ds_hold.getRowPosition(),"wt", ds_hold.getCellData(bfRow,"wt"));
    ds_hold.setCellData(ds_hold.getRowPosition(),"cbm", ds_hold.getCellData(bfRow,"cbm"));
};

scwin.f_gridToExcel = function (argGrid, argTitle) {
    // Title
    // argGrid.SetExcelTitle(0, "");
    // argGrid.SetExcelTitle(1,"value:" + argTitle + ";" // 표시할 타이틀
    //                       + "font-face:'돋움체';"      // 폰트
    //                       + "font-size:16pt;"         // 폰트 크기
    //                       + "font-color:black;"       // 폰트 색깔
    //                       + "bgcolor:#ffffff;"        // 배경 색깔
    //                       + "align:center;"           // 정렬
    //                       + "line-color:white;"       // 타이틀 부분 테두리선 색깔
    //                       + "line-width:0pt;"         // 타이틀 테두리선 굵기
    //                       + "skiprow:1;");            // 타이틀 다음 떼는 로우 수
    // // 검색조건
    var vDay = "점소 | " + acb_lobranCd.getText(true) + " | "
             + "입항예정일자 | " + ica_arvStDt.getValue() + " ~ " + ica_arvEndDt.getValue();
    // var vSearchOption = ";font-face:굴림체;font-size:10pt;font-color:black;bgcolor:#ffffff;align: left;line-color:red;line-width:0pt;";
    // argGrid.SetExcelTitle(1, "value:" + vDay.replace(/:/g,'|').replace(/;/g,'') + vSearchOption );
    // cfGridToExcel(argGrid, argTitle, argTitle+".xls", 4+8+16);

    var argGridTotalCol = 0;
    for (var i = 0 ; i < argGrid.getTotalCol(); i++) {
        if (argGrid.getColumnVisible(i)) {
            argGridTotalCol++;
        }
    }

    const infoArr = [
        {
          rowIndex    : 0
        , colIndex    : 0
        , rowSpan     : 1
        , colSpan     : argGridTotalCol
        , text        : argTitle
        , textAlign   : "center"
        , fontSize    : "24"
        , fontName    : "돋움체"
        , color       : "black"
        , fontWeight  : ""
        , drawBorder  : "false"
        , borderColor : ""
        , borderWidth : ""
        , wordWrap    : "true"
        , bgColor     : "#ffffff"
    }
    ,{
          rowIndex    : 2
        , colIndex    : 0
        , rowSpan     : 1
        , colSpan     : argGridTotalCol
        , text        : vDay
        , textAlign   : "left"
        // , fontSize    : "12pt"
        , fontName    : "돋움체"
        , color       : "black"
        , fontWeight  : ""
        , drawBorder  : "false"
        , borderColor : ""
        , borderWidth : ""
        , wordWrap    : "true"
        , bgColor     : "#ffffff"
    }
    ];
    const options = {
        fileName : argTitle + ".xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: argTitle,
        type : "1",
        startRowIndex: 3,
        // removeColumns: "0,21",
        // hiddenVisible : true,
        // useSubTotal :"true", 
        // useSubTotalData  : "true",
        // oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
        // evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
    };
    $c.data.downloadGridViewExcel(argGrid, options, infoArr);
}

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_openPopUP1 = function () {
	if (ed_vsslCfNm.getValue() == "") {
		ed_empNo.setValue("");
	} else {
		scwin.f_openCommonPopUpForMan(1,'T');
	}
};

scwin.f_openCommonPopUpForMan = async function (disGubun, pWinCloseTF) {
  	// 선언부
  	var sWinCloseTF = (pWinCloseTF == null) ? "T" : pWinCloseTF;
	var rtnList  = new Array();  // 공통POP-UP -> 요청화면 
	var pCode = "";
	var pName = "";
	var pWtitleSearch = "";
	var arrParam = new Array();

	switch (disGubun) {
  		case 1:	//정규직(grid)
			pCode = ed_empNo.getValue();
			pName = ed_vsslCfNm.getValue();

            var item = acb_lobranCd.getSelectedRow()
 			arrParam[0] = pCode; //사번
            arrParam[1] = pName; //사원명
            arrParam[2] = item.value; //점소코드
            arrParam[3] = item.label; //점소명
            arrParam[4] = ''; //작업장코드
            arrParam[5] = '01,D';//직종  (정규직)
            arrParam[6] = '02,D' //상세직종코드 (하역직)
            arrParam[7] = ''; //직급
            arrParam[8] = '';  //작업일
            arrParam[9] = 'Y'; //배치가능여부
 			arrParam[10] = sWinCloseTF; //WINDOW CLOSE 여부
 			arrParam[11] = "1"; //상세직종Flag

 			// rtnList = window.showModalDialog("/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.jsp", arrParam, "dialogHeight:450px; dialogWidth:530px; resizable=no; help:no; status:no; center=true; "); 	
            var win_url = "/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.xml";
            var opts = {
                  id : "1Pop"
                , popupName : "인력검색"
                , modal : true
                , type : "browserPopup"
                , width : 1100
                , height : 630
                , popupTitle : "인력검색"
            };
            var rtnList = await $c.win.openPopup(win_url, opts, arrParam);

 		    //(0)직종코드		
			//(1)직종명	        
            //(2)인원번호		
            //(3)인원명	                          
            //(4)직급		    
            //(5)직급명		    
            //(6)물류점소코드   
            //(7)물류점소명		
            //(8)상세직종코드	
            //(9)상세직종명		                  
            //(10)배치가능여부	
            //(11)본사계약직여부 
            //(12)연근여부		

 			if (rtnList != null && rtnList[3] != undefined) {
 				if (rtnList[3] == undefined) {
					return;
		 		}
			    ed_empNo.setValue(rtnList[2]);	//사원코드
			    ed_vsslCfNm.setValue(rtnList[3]);	//사원명
			    return;
			}  else {
		 		ed_empNo.setValue("");	//사원코드
			    ed_vsslCfNm.setValue("");	//사원명
		 	}
		 	break;
	}
};

//-------------------------------------------------------------------------
// 그리드 팝업
//-------------------------------------------------------------------------  
scwin.f_openCommPopUpGrid = async function (gubun, row, pClose) {
    // 선언부
	var rtnList;  // 공통POP-UP -> 요청화면 
	var pWhere;		// 조회조건
	var pCode = "";
    var pName = "";	
    var arrParam = new Array();	
   	var sWinCloseTF = (pClose == null) ? "T" : pClose;
	switch (gubun) {
  		case 1:
			//chief포맨
  			pCode = ds_cvsslInfo.getCellData(row, "cfmanEmpNo");
			pName = "";
             var item = acb_lobranCd.getSelectedRow()
 			arrParam[0] = pCode; //사번
            arrParam[1] = pName; //사원명
            arrParam[2] = item.value; //점소코드
            arrParam[3] = item.label; //점소명
            arrParam[4] = ''; //작업장코드
            arrParam[5] = '01,D';//직종  (정규직)
            arrParam[6] = '02,D' //상세직종코드 (하역직)
            arrParam[7] = ''; //직급
            arrParam[8] = '';  //작업일
            arrParam[9] = 'Y'; //배치가능여부
 			arrParam[10] = sWinCloseTF; //WINDOW CLOSE 여부
 			arrParam[11] = "1"; //상세직종Flag

 			// rtnList = window.showModalDialog("/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.jsp", arrParam, "dialogHeight:450px; dialogWidth:530px; resizable=no; help:no; status:no; center=true; "); 	
            var win_url = "/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.xml";
            var opts = {
                  id : "1Pop"
                , popupName : "인력검색"
                , modal : true
                , type : "browserPopup"
                , width : 1100
                , height : 630
                , popupTitle : "인력검색"
            };
            var rtnList = await $c.win.openPopup(win_url, opts, arrParam);

 		    //(0)직종코드		
			//(1)직종명	        
            //(2)인원번호		
            //(3)인원명	                          
            //(4)직급		    
            //(5)직급명		    
            //(6)물류점소코드   
            //(7)물류점소명		
            //(8)상세직종코드	
            //(9)상세직종명		                  
            //(10)배치가능여부	
            //(11)본사계약직여부 
            //(12)연근여부		

 			if (rtnList != null && rtnList[3] != undefined) {
 				if (rtnList[3] == undefined) {
					return;
		 		}
			    ds_cvsslInfo.setCellData(row, "cfmanEmpNo", rtnList[2]);	//사원코드
			    ds_cvsslInfo.setCellData(row, "cfmanEmpNm", rtnList[3]);	//사원명
			    return;
			}  else {
		 		ds_cvsslInfo.setCellData(row, "cfmanEmpNo", "");	//사원코드
			    ds_cvsslInfo.setCellData(row, "cfmanEmpNm", "");	//사원명
		 	}
			break;

	    case 2:
		// 품명 팝업	
			pCode = ds_hold.getCellData(row,"commCd");
			pName = "";

            udc_popup.setSelectId('retrieveCommInfo');
			udc_popup.cfCommonPopUp(function(rtnList){
                                if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
                                    ds_hold.setCellData(row,"commCd", rtnList[0]);
                                    ds_hold.setCellData(row,"commNm", rtnList[1]);
                                } else {			 
                                    ds_hold.setCellData(row,"commNm", "");
                                    ds_hold.setCellData(row,"commCd", "");
                                }	
                            }	// XML상의 SELECT ID	
							,pCode					// 화면에서의 ??? Code Element의	Value
							,pName					// 화면에서의 ??? Name Element의	Value
							,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
							,'3'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
							,'품목/품명코드,품목/품명,구분'					// Title순서	
							,'105,190,70'					// 보여주는 각 컬럼들의 폭	
