scwin.uploadComplete = async function (isSuccess) { 
    if (!isSuccess) return;

    // for (var i = 0 ; i < ds_fileUploadGDS.getRowCount(); i++) {
    //     var rowIndex = ds_attach.insertRow();
    //     ds_attach.setRowPosition(rowIndex);
    //     if (ds_attach.getRowCount() != 1 ) {
    //         var fltNxtSeq = parseFloat(ds_attach.getCellData(ds_attach.getRowCount() - 1,"attachFileId")) + 1;
    //         var strNxtSeq = "000" + fltNxtSeq;
    //         strNxtSeq = strNxtSeq.substr(strNxtSeq.length - 4, strNxtSeq.length);           
    //         ds_attach.setCellData(ds_attach.getRowCount(),"attachFileId", strNxtSeq);
    //     } else {
    //         ds_attach.setCellData(ds_attach.getRowCount(),"attachFileId", "0001");
    //     }
    //     ds_attach.setCellData(ds_attach.getRowCount(), "attachFileNm", ds_fileUploadGDS.getCellData(i,"filename"));                               //파일명
    //     ds_attach.setCellData(ds_attach.getRowCount(), "attachFileDesc", ds_fileUploadGDS.getCellData(i,"filename"));                             //파일설명
    //     ds_attach.setCellData(ds_attach.getRowCount(), "attachFileSiz", ds_fileUploadGDS.getCellData(i,"fileSize"));                              //파일SIZE
    //     ds_attach.setCellData(ds_attach.getRowCount(), "attachFilePath", ds_fileUploadGDS.getCellData(i,"filepath"));                             //파일경로
    //     ds_attach.setCellData(ds_attach.getRowCount(), "salesActivId", ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(),"cvsslMgntNo"));    //파일ID
    //     ds_attach.setCellData(ds_attach.getRowCount(), "cvsslMgntNo", ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(),"cvsslMgntNo"));    
    // }
    // $c.sbm.execute(sbm_saveFile);

    var modifyData = gr_attachFile.getModifiedData();
    var attachData = gr_attachFile.getData();
    var attachRowCnt = attachData.length;
    var modifyRowCnt = modifyData.length;

    // var jsonData = [];
    // for (var i = 0 ; i < attachData.length ; i ++) {
    //     var fileData = {
    //           "chk"               : attachData[i].chk
    //         , "FILE_STORED_PATH"  : attachData[i].FILE_STORED_PATH
    //         , "STORED_FILE_NM"    : attachData[i].STORED_FILE_NM
    //         , "ORIGIN_FILE_NM"    : attachData[i].ORIGIN_FILE_NM
    //         , "FILE_EXPLAIN"      : attachData[i].FILE_EXPLAIN
    //         , "FILE_SIZE"         : attachData[i].FILE_SIZE
    //         , "slipNo"            : attachData[i].slipNo
    //         , "slipKndNm"         : attachData[i].slipKndNm
    //         , "evidClsNm"         : attachData[i].evidClsNm
    //         , "receptYn"          : attachData[i].receptYn
    //         , "status"            : attachData[i].status
    //         , "hiddenKey"         : attachData[i].hiddenKey
    //         , "preView"           : attachData[i].preView
    //         , "rowStatus"         : attachData[i].rowStatus
    //     }
    //     jsonData.push(fileData);
    // }
    // scwin.tempAttachData = jsonData;

    ds_fileUploadGDS.sort("fileId", "1");

	for ( i = 0 ; i < attachRowCnt; i++) {
        if (attachData[i].status == "Completed"){
            var rowIndex = ds_attach.insertRow();
            ds_attach.setRowPosition(rowIndex);
            if (rowIndex != 0) {
                var fltNxtSeq = parseFloat(ds_attach.getCellData(rowIndex - 1, "attachFileId")) + 1;
                var strNxtSeq = "000" + fltNxtSeq;
                // strNxtSeq = strNxtSeq.substr(strNxtSeq.length - 4, strNxtSeq.length);
                ds_attach.setCellData(rowIndex,"attachFileId", strNxtSeq);
            } else {
                ds_attach.setCellData(rowIndex,"attachFileId", "0001");
            }
            ds_attach.setCellData(rowIndex, "attachFileNm"   , attachData[i].ORIGIN_FILE_NM); //파일명
            ds_attach.setCellData(rowIndex, "attachFileDesc" , attachData[i].FILE_EXPLAIN); //파일설명
            ds_attach.setCellData(rowIndex, "attachFileSiz"  , attachData[i].FILE_SIZE); //파일SIZE
            ds_attach.setCellData(rowIndex, "attachFilePath" , attachData[i].FILE_STORED_PATH + attachData[i].STORED_FILE_NM);	//파일경로

            ds_attach.setCellData(rowIndex, "salesActivId"   , ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(),"cvsslMgntNo"));    //파일ID
            ds_attach.setCellData(rowIndex, "cvsslMgntNo"    , ds_cvsslInfo.getCellData(ds_cvsslInfo.getRowPosition(),"cvsslMgntNo"));    
            ds_attach.modifyRowStatus(i, "C");
        }
	}
    var allJson = ds_attach.getAllJSON();
    for (var i = 0 ; i < ds_attach.getRowCount() ; i++){
        var targetName = allJson[i].attachFilePath.substr(allJson[i].attachFilePath.lastIndexOf('/')+1)
        for (var j = 0 ; j < modifyRowCnt ; j++){
            if (targetName == modifyData[j].STORED_FILE_NM){
                if (modifyData[j].rowStatus == "E"){
                    ds_attach.modifyRowStatus(i, "D");
                    break;
                } else if (modifyData[j].rowStatus == "U"){
                    ds_attach.modifyRowStatus(i, "U");
                    ds_attach.setCellData(i, "attachFileDesc", modifyData[j].FILE_EXPLAIN);
                    break;
                }
            }
        }
    }
    if (ds_attach.getRowCount() == 0){
        await $c.win.alert("저장할 내역이 없습니다.");
        return false;
    }     
    if (await $c.win.confirm("저장 하시겠습니까?")) {
        $c.sbm.execute(sbm_saveFile);
    }
};

//-------------------------------------------------------------------------
// function name : scwin.f_Download
//-------------------------------------------------------------------------
scwin.f_Download = async function () {
    var row = ds_attach.getRowPosition();
    if (row < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["첨부파일 행"]);
        return;
    } else {
        var fileName = ds_attach.getCellData(row, "attachFileNm");
        var filePath = ds_attach.getCellData(row, "attachFilePath");
        if (filePath.trim().length == 0) {
            await $c.win.alert("선택하신 " + row + "행에 파일이 등록되어 있지 않습니다.");
        } else {
            if (filePath.indexOf(".") > 0) {
                fileName += filePath.substring(filePath.indexOf("."), filePath.indexOf(".")+4);
                $c.gus.cfDownloadFile(fileName , filePath);
            }
        }
    }
};

