            break;
	}
};

scwin.gr_cvsslInfo_onafteredit = function (row, columnIndex, value) {
    var colid = gr_cvsslInfo.getColumnID(columnIndex);
    var newData = ds_cvsslInfo.getCellData(row, columnIndex);
    switch (colid) {
		case "cfmanEmpNo":
            var oldData = scwin.oldData1
			if (newData != "" 
             && newData != oldData){
				ds_cvsslInfo.setCellData(row,"cfmanEmpNm","");
				scwin.f_openCommPopUpGrid(1,row, 'T');
			} else if (newData == "") {
				ds_cvsslInfo.setCellData(row,"cfmanEmpNo","");
				ds_cvsslInfo.setCellData(row,"cfmanEmpNm","");
			}
            break;
		case "cfmanEmpNm":
            var oldData = scwin.oldData4
			if (newData != "" 
             && newData != oldData){
				ds_cvsslInfo.setCellData(row,"cfmanEmpNo","");
				scwin.f_openCommPopUpGrid(4,row, 'T');
			} else if (newData == "") {
				ds_cvsslInfo.setCellData(row,"cfmanEmpNo","");
				ds_cvsslInfo.setCellData(row,"cfmanEmpNm","");
			}
            break;
	}
};

