scwin.gr_hold_onafteredit = function (row, columnIndex, value) {
    var colid = gr_hold.getColumnID(columnIndex);
    var newData = gr_hold.getCellData(row, columnIndex);
    switch (colid) {
        case "commCd":
            var oldData = scwin.oldData2
			if (newData != "" 
             && newData != oldData){
				ds_hold.setCellData(row,"commNm","");
				scwin.f_openCommPopUpGrid(2,row, 'T');
			} else if (newData == "") {
				ds_hold.setCellData(row,"commCd","");
				ds_hold.setCellData(row,"commNm","");
			}
		    break;

		case "commNm":
            var oldData = scwin.oldData3
			if (newData != "" 
             && newData != oldData){
				ds_hold.setCellData(row,"commCd","");
				scwin.f_openCommPopUpGrid(3,row, 'T');
			} else if (newData == "") {
				ds_hold.setCellData(row,"commCd","");
				ds_hold.setCellData(row,"commNm","");
			}
		    break;

        case "qty":
			if (ds_hold.getCellData(row, "qty") == 0) {
                ds_hold.setCellData(row, "qty", 0);
            }
		    break;
		case "wt":
			if (ds_hold.getCellData(row, "wt") == 0) {
                ds_hold.setCellData(row, "wt", 0);
            }
		    break;
		case "cbm":
			if (ds_hold.getCellData(row, "cbm") == 0) {
                ds_hold.setCellData(row, "cbm", 0);
            }
		    break;
    }
};

